import{_ as r,o as a,c as l,ae as e}from"./chunks/framework.DrYEjkpc.js";const c=JSON.parse('{"title":"EvoSkill","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-evoskill.md","filePath":"radar/tech-evoskill.md"}'),o={name:"radar/tech-evoskill.md"};function i(n,t,s,h,d,u){return a(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="evoskill" tabindex="-1">EvoSkill <a class="header-anchor" href="#evoskill" aria-label="Permalink to &quot;EvoSkill&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 生成 / Skill 优化 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.53</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: <strong>三 Agent 协作</strong>（Executor / Proposer / Skill-Builder）从失败轨迹中自动诊断&quot;卡在哪&quot;并物化为 Skill。</p><p><strong>来源</strong>:</p><ul><li>工业 + 学术 - Sentient AGI</li><li>论文 + 开源</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2603.02766" target="_blank" rel="noreferrer">arXiv 2603.02766</a></li><li>GitHub：<a href="https://github.com/sentient-agi/EvoSkill" target="_blank" rel="noreferrer">sentient-agi/EvoSkill</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to &quot;核心原理&quot;">​</a></h3><p>不依赖人类作者，从失败循环中自动生长 Skill：</p><ol><li><strong>Executor</strong> 执行任务并记录轨迹</li><li><strong>Proposer</strong> 分析失败轨迹，诊断根因（如&quot;Agent 不知道要等 DOM 稳定再抽取&quot;）</li><li><strong>Skill-Builder</strong> 将诊断结果物化为结构化 Skill 文件夹</li></ol><h3 id="关键机制" tabindex="-1">关键机制 <a class="header-anchor" href="#关键机制" aria-label="Permalink to &quot;关键机制&quot;">​</a></h3><ul><li><strong>Pareto 前沿选择 + Git 管理</strong> — 每个变体在验证集上跑分，只有在所有维度都不被超越的才保留。每个变体存为独立 Git 分支。</li><li><strong>关键数字</strong> — 在 <strong>OfficeQA 上 +7.3%、SealQA 上 +12.1%</strong>（验证 Skill 进化对实际任务的提升）。</li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h3><ul><li>自动失败归因</li><li>Pareto 多维选择</li><li>Skill 进化历史可追溯</li></ul><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>依赖 <strong>ground-truth 信号</strong>（必须知道&quot;对了还是错了&quot;才能诊断）</li><li>在开放式任务（没有明确成功标准）上受限</li><li>主要在 OfficeQA / SealQA 基准上验证</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.55</td><td>论文 + 开源实现</td></tr><tr><td>创新性</td><td>0.80</td><td>三 Agent 协作 + Pareto 选择是新颖设计</td></tr><tr><td>落地程度</td><td>0.35</td><td>学术验证阶段</td></tr><tr><td>生态活跃度</td><td>0.40</td><td>Sentient AGI 维护</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.53</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2603.02766" target="_blank" rel="noreferrer">EvoSkill 论文</a></li><li><a href="https://github.com/sentient-agi/EvoSkill" target="_blank" rel="noreferrer">GitHub</a></li></ul>',29)])])}const k=r(o,[["render",i]]);export{c as __pageData,k as default};
